const x = msg.payload['project/node1/x'];
const y = msg.payload['project/node1/y'];
const z = msg.payload['project/node1/z'];
msg.payload = `X: ${x} | Y: ${y} | Z: ${z}`;
return msg;

let v = Number(msg.payload);
if (!isNaN(v)) msg.payload = (v / 1e6).toFixed(1) + ' MHz';
return msg;

if (msg.payload === 1 || msg.payload === '1' || msg.payload === true || msg.payload === 'true') {
    msg.payload = 'Station Detected';
} else {
    msg.payload = 'No Signal';
}
return msg;

let p = msg.payload;
if (!Array.isArray(p)) return null;
msg.payload = p.map((x, i) => `#${i+1} -> ${(x.freq_hz/1e6).toFixed(1)} MHz | ${x.power_db} dB`).join('\n');
return msg;

let freqHz = Number(msg.payload.freq);
let pwr = Number(msg.payload.power);
if (isNaN(freqHz) || isNaN(pwr)) return null;
let line = new Date().toLocaleTimeString('en-GB', {hour12:false}) + ' | ' + (freqHz/1e6).toFixed(1) + ' MHz | ' + pwr.toFixed(2) + ' dB';
let hist = flow.get('sdr_hist_lines') || [];
hist.unshift(line);
if (hist.length > 10) hist = hist.slice(0, 10);
flow.set('sdr_hist_lines', hist);
msg.payload = hist.join('\n');
return msg;

let p = msg.payload;
if (!p || !Array.isArray(p.spectrum)) return null;

let row = p.spectrum.map(item => Number(item.power_db.toFixed(2)));
let xLabels = p.spectrum.map(item => Number((item.freq_offset_hz / 1000).toFixed(1)));
let centerFreqHz = Number(p.center_freq_hz || 100000000);

let matrix = flow.get('wf_matrix_full') || [];
matrix.unshift(row);

const MAX_ROWS = 30;
if (matrix.length > MAX_ROWS) {
    matrix = matrix.slice(0, MAX_ROWS);
}

flow.set('wf_matrix_full', matrix);

msg.payload = {
    x: xLabels,
    z: matrix,
    center_freq_hz: centerFreqHz
};
return msg;

msg.payload = "X: " + msg.payload["project/motor/accelX"] +
              " | Y: " + msg.payload["project/motor/accelY"] +
              " | Z: " + msg.payload["project/motor/accelZ"];

return msg;

let vibration = Number(msg.payload);

let readings = context.get("readings") || [];

readings.push(vibration);
if (readings.length > 10) readings.shift();

context.set("readings", readings);

let avg = readings.reduce((a, b) => a + b, 0) / readings.length;

// Output 1 → للـ Gauge (القيمة)
let output1 = { payload: vibration };

// Output 2 → للـ Text (الحالة)
let output2;

if (avg < 4000) {
    output2 = { payload: "🟢 Normal" };
} else if (avg < 8000) {
    output2 = { payload: "🟡 Warning" };
} else {
    output2 = { payload: "🔴 Critical Vibration" };
}
if (avg > 8000) {
    // يرسل أمر إيقاف
    return [
        output1,
        output2,
        { topic: "project/motor/control/set", payload: 0 }
    ];
}

return [output1, output2];
